SELECT sku, path, brand, series, model, name, json_extract(properties,'$.cleaning_type') AS cleaning_type, json_extract(properties,'$.pack_count') AS pack_count
FROM products
WHERE brand='Vileda' AND (
  name LIKE '%Mop%' OR name LIKE '%Wipe%' OR series LIKE '%Vileda Pro Easy%' OR model LIKE '%1XB-2OF%'
)
LIMIT 50;
